mapper.select:
SELECT us.user_id, team.team_id, team.team_name, post.post_id, post.post_name, us.user_name, us.user_name_kana, us.password, us.role, us.retirement_flg, us.version FROM m_user us LEFT OUTER JOIN m_user_team user_team ON us.user_id = user_team.user_id LEFT OUTER JOIN m_team team ON user_team.team_id = team.team_id LEFT OUTER JOIN m_post post ON us.post_id = post.post_id
us.retirement_flg = #{retirementFlg}
and us.user_id = #{userId}
ORDER BY us.retirement_flg ASC, us.post_id ASC, team.team_id ASC
